import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"43. Ceremonial Leave","description":"","frontmatter":{"title":"43. Ceremonial Leave","eba":"Mental Health Services 2024-2028","topics":["leave","ceremonial-leave","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/43-ceremonial-leave.md","filePath":"ebas/mental-health/common-terms/leave/43-ceremonial-leave.md"}'),n={name:"ebas/mental-health/common-terms/leave/43-ceremonial-leave.md"};function i(s,e,l,p,m,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_43-ceremonial-leave" tabindex="-1">43. Ceremonial Leave <a class="header-anchor" href="#_43-ceremonial-leave" aria-label="Permalink to &quot;43. Ceremonial Leave&quot;">​</a></h1><p><strong>43.1</strong> General</p><p><strong>(a)</strong> In addition to any paid leave entitlement below, an Employee who is required by Aboriginal and Torres Strait Islander tradition to be absent from work for ceremonial purposes will also be entitled to up to ten working days&#39; unpaid leave in any one year, with the approval of the Employer.</p><p><strong>43.2</strong> NAIDOC Week Leave</p><p><strong>(a)</strong> An Employee of Aboriginal or Torres Strait Islander descent is entitled to one day of paid leave per calendar year to participate in National Aboriginal and Islander Day Observance Committee (NAIDOC) week or similar activities and events not otherwise covered by 43.3.</p><p><strong>(b)</strong> NAIDOC week leave does not accrue from year to year and is not paid out on termination of employment.</p><p><strong>(c)</strong> Where an Employer receives a request to substitute a public holiday in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clause 98.4</a>[104.4] of this Agreement for a day during NAIDOC week, the Employer will consider all the circumstances including:</p><p><strong>(i)</strong> any reason identified by the Employee with respect to the request; and</p><p><strong>(ii)</strong> the operational requirements of the Employer.</p><p><strong>(d)</strong> An Employer will not unreasonably refuse a request to substitute a public holiday under this subclause.</p><p><strong>43.3</strong> Ceremonial Leave</p><p><strong>(a)</strong> Aboriginal and/or Torres Strait Islander Employees are entitled to three days&#39; paid leave in each year of employment for ceremonial purposes that are:</p><p><strong>(i)</strong> connected with the death of a member of the Immediate family or extended family; or</p><p><strong>(ii)</strong> for other ceremonial obligations under Aboriginal and Torres Strait Islander lore.</p><p><strong>(e)</strong> For the purposes of this subclause, “extended family” has a meaning that recognises that extended families exist within Aboriginal and/or Torres Strait Islander society and obligations of Aboriginal and/or Torres Strait Islander Employees may exist regardless of the existence of a bloodline relationship or not. Family also extends to cover relationships where there is a close association, which need not be a blood relationship.</p><p><strong>(b)</strong> Paid Ceremonial Leave will not accrue from year to year and is not paid out on termination of employment.</p><p><strong>(c)</strong> Leave granted under this clause is in addition to Compassionate Leave.</p><p><strong>(d)</strong> To support the Employee in fulfilling their ceremonial obligations, the Employee may also access any other accrued leave, time in lieu, or otherwise may be granted unpaid leave in accordance with the requirements of those entitlements.</p><p><strong>43.4</strong> Leave to participate in the First Peoples&#39; Assembly of Victoria</p><p><strong>(a)</strong> An Employee who is a member of the First Peoples Assembly of Victoria is entitled to up to 10 days&#39; paid leave per calendar year to fulfil their official functions during their term of office.</p><p><strong>(b)</strong> Leave will be available to attend sessions of the First Peoples’ Assembly of Victoria to participate in constituent consultation relevant to their role or for any other ancillary purpose as agreed with the Employer.</p><p><strong>(c)</strong> Leave under this clause will not accrue from year to year and is not paid out on termination of employment.</p><p><strong>(d)</strong> Where in any calendar year an Employee exhausts their entitlement under this clause, the Employer may grant further paid or unpaid leave to support their Employee’s representative functions.</p><p><strong>(e)</strong> The Employee may also utilise flexible working arrangements, in addition to leave provided in this clause, to help support their representative functions, with the agreement of the Employer.</p><p>Plain language terms: cultural leave, sorry business, aboriginal ceremony, religious ceremony, funeral.</p>',25)])])}const g=t(n,[["render",i]]);export{h as __pageData,g as default};
